indexStyle:
/* ========== 首页文章卡片（修复DOM类名不匹配） ========== */
.blog-post {
    border-left: 4px solid #3b82f6;
    border-radius: 8px;
    padding: 20px 24px;
    margin-bottom: 20px;
    background: var(--bgColor-default, #fff);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.blog-post:hover {
    transform: translateY(-4px);
    box-shadow: 0 8px 24px rgba(0,0,0,0.08);
}
.blog-post h2 a {
    font-size: 1.4em;
    color: var(--fgColor-default, #1f2328);
    text-decoration: none;
}
.blog-post .post-meta {
    font-size: 0.85em;
    color: var(--fgColor-muted, #656d76);
    margin-top: 8px;
}

/* ========== 搜索面板（修复JSON转义 + 暗色适配） ========== */
.search-panel {
    background: rgba(255,255,255,0.95) !important;
    backdrop-filter: blur(12px);
}
.search-close::before { content: "\2715"; }

/* ========== 阅读进度条（暗色适配） ========== */
.progress-track { background: #e5e7eb !important; }
.progress-bar { background: linear-gradient(90deg, #3b82f6, #8b5cf6) !important; }

/* ========== 全局暗色模式覆盖 ========== */
@media (prefers-color-scheme: dark) {
    .blog-post {
        background: var(--bgColor-default, #0d1117) !important;
        border-left-color: #58a6ff !important;
    }
    .blog-post:hover { box-shadow: 0 8px 24px rgba(0,0,0,0.3) !important; }
    .search-panel { background: rgba(22,27,34,0.95) !important; }
    .progress-track { background: #30363d !important; }
    code.copy-btn { background: #21262d !important; color: #c9d1d9 !important; }
}

/* ========== 樱花Canvas防遮挡 ========== */
#sakura-canvas {
    position: fixed !important;
    top: 0; left: 0;
    width: 100%; height: 100%;
    pointer-events: none !important;
    z-index: 9999 !important;
}

indexScript:
(function() {
    'use strict';

    /* ===== 安全初始化封装（解决异步渲染时序问题） ===== */
    function safeInit(selector, callback, maxRetries) {
        maxRetries = maxRetries || 10;
        var retries = 0;
        var timer = setInterval(function() {
            var el = document.querySelector(selector);
            if (el) {
                clearInterval(timer);
                callback(el);
            } else if (++retries >= maxRetries) {
                clearInterval(timer);
                console.warn('[Luliy] Element not found after retries:', selector);
            }
        }, 300);
    }

    /* ===== 阅读进度条 + 回顶按钮 ===== */
    safeInit('.markdown-body', function(article) {
        if (!document.querySelector('.progress-track')) {
            var track = document.createElement('div');
            track.className = 'progress-track';
            track.innerHTML = '<div class="progress-bar" style="width:0%"></div>';
            Object.assign(track.style, {
                position:'fixed', top:'0', left:'0', width:'100%',
                height:'3px', zIndex:'10000', background:'#e5e7eb'
            });
            document.body.appendChild(track);
        }

        if (!document.querySelector('.back-to-top')) {
            var btn = document.createElement('div');
            btn.className = 'back-to-top';
            btn.textContent = '\u2191';
            Object.assign(btn.style, {
                position:'fixed', bottom:'30px', right:'30px',
                width:'44px', height:'44px', borderRadius:'50%',
                background:'#3b82f6', color:'#fff', display:'flex',
                alignItems:'center', justifyContent:'center',
                cursor:'pointer', zIndex:'10000', opacity:'0',
                transition:'opacity 0.3s', fontSize:'18px'
            });
            btn.onclick = function() { window.scrollTo({top:0,behavior:'smooth'}); };
            document.body.appendChild(btn);
        }

        window.addEventListener('scroll', function() {
            var rect = article.getBoundingClientRect();
            var total = article.scrollHeight - window.innerHeight;
            var progress = Math.min(100, Math.max(0, (-rect.top / total) * 100));
            var bar = document.querySelector('.progress-bar');
            var btt = document.querySelector('.back-to-top');
            if (bar) bar.style.width = progress + '%';
            if (btt) btt.style.opacity = window.scrollY > 300 ? '1' : '0';
        });
    });

    /* ===== 樱花特效（修复Canvas遮挡） ===== */
    safeInit('body', function(body) {
        if (document.getElementById('sakura-canvas')) return;
        var canvas = document.createElement('canvas');
        canvas.id = 'sakura-canvas';
        Object.assign(canvas.style, {
            position:'fixed', top:'0', left:'0',
            width:'100%', height:'100%',
            pointerEvents:'none', zIndex:'9999'
        });
        body.appendChild(canvas);

        var ctx = canvas.getContext('2d');
        var petals = [];
        function resize() { canvas.width = window.innerWidth; canvas.height = window.innerHeight; }
        window.addEventListener('resize', resize);
        resize();

        for (var i = 0; i < 30; i++) {
            petals.push({
                x: Math.random()*canvas.width, y: Math.random()*canvas.height,
                r: 4+Math.random()*6, dx: 0.5+Math.random(), dy: 1+Math.random()*1.5,
                o: 0.3+Math.random()*0.5
            });
        }
        function draw() {
            ctx.clearRect(0,0,canvas.width,canvas.height);
            petals.forEach(function(p) {
                ctx.beginPath();
                ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
                ctx.fillStyle = 'rgba(255,183,197,'+p.o+')';
                ctx.fill();
                p.x += p.dx; p.y += p.dy;
                if (p.y > canvas.height) { p.y = -10; p.x = Math.random()*canvas.width; }
                if (p.x > canvas.width) { p.x = -10; }
            });
            requestAnimationFrame(draw);
        }
        draw();
    });
})();
